// Elasticsearch Service
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.index.query.QueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

@Service
public class ElasticsearchService {
    @Autowired
    private RestHighLevelClient client;

    private final String indexName = "products";

    public void indexProduct(Product product) throws IOException {
        Map<String, Object> productMap = new HashMap<>();
        productMap.put("name", product.getName());
        productMap.put("description", product.getDescription());
        productMap.put("price", product.getPrice());
        productMap.put("category", product.getCategory());

        IndexRequest indexRequest = new IndexRequest(indexName).id(product.getId()).source(productMap);
        client.index(indexRequest, RequestOptions.DEFAULT);
    }

    public SearchResponse searchProducts(String query) throws IOException {
        QueryBuilder queryBuilder = QueryBuilders.multiMatchQuery(query, "name", "description");
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder().query(queryBuilder);

        SearchRequest searchRequest = new SearchRequest(indexName).source(sourceBuilder);
        return client.search(searchRequest, RequestOptions.DEFAULT);
    }

    public SearchResponse facetedSearch(String query, String facetField) throws IOException {
        QueryBuilder queryBuilder = QueryBuilders.multiMatchQuery(query, "name", "description");
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder().query(queryBuilder);
        sourceBuilder.aggregation(AggregationBuilders.terms("facet").field(facetField));

        SearchRequest searchRequest = new SearchRequest(indexName).source(sourceBuilder);
        return client.search(searchRequest, RequestOptions.DEFAULT);
    }
}

// Product Controller
import org.elasticsearch.action.search.SearchResponse;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;

@RestController
@RequestMapping("/products")
public class ProductController {
    @Autowired
    private ElasticsearchService elasticsearchService;

    @PostMapping
    public ResponseEntity<String> indexProduct(@RequestBody Product product) {
        try {
            elasticsearchService.indexProduct(product);
            return ResponseEntity.ok("Product indexed successfully");
        } catch (IOException e) {
            return ResponseEntity.status(500).body("Error indexing product");
        }
    }

    @GetMapping("/search")
    public ResponseEntity<SearchResponse> searchProducts(@RequestParam String query) {
        try {
            SearchResponse response = elasticsearchService.searchProducts(query);
            return ResponseEntity.ok(response);
        } catch (IOException e) {
            return ResponseEntity.status(500).body(null);
        }
    }

    @GetMapping("/facets")
    public ResponseEntity<SearchResponse> facetedSearch(@RequestParam String query, @RequestParam String facetField) {
        try {
            SearchResponse response = elasticsearchService.facetedSearch(query, facetField);
            return ResponseEntity.ok(response);
        } catch (IOException e) {
            return ResponseEntity.status(500).body(null);
        }
    }
}